#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <cmath>
#include <iostream>
#include <string>
#include <vector>
#include <omp.h>

#define MAX_THREADS_PER_BLOCK 256

struct Node {
    int starting;
    int no_of_edges;
};

int work_group_size = 512;
int platform_id_inuse = 0;
int device_id_inuse = 0;

#ifdef PROFILING
class timer {
public:
    timer(const char * = 0) : total_time(0.0), start_time(0.0), running(false) {}
    timer(const char *, std::ostream &) : total_time(0.0), start_time(0.0), running(false) {}
    ~timer() {}
    void start() {
        running = true;
        start_time = omp_get_wtime();
    }
    void stop() {
        if (running) {
            total_time += omp_get_wtime() - start_time;
            running = false;
        }
    }
    void reset() {
        total_time = 0.0;
        start_time = 0.0;
        running = false;
    }
    double getTimeInSeconds() {
        return total_time;
    }

private:
    double total_time;
    double start_time;
    bool running;
};
#endif

#ifdef TIMING
#include <sys/time.h>
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;

static inline void tvsub(const struct timeval *t1, const struct timeval *t0, struct timeval *res) {
    res->tv_sec = t1->tv_sec - t0->tv_sec;
    res->tv_usec = t1->tv_usec - t0->tv_usec;
    if (res->tv_usec < 0) {
        --res->tv_sec;
        res->tv_usec += 1000000;
    }
}
#endif

template<typename datatype>
void compare_results(const datatype *cpu_results, const datatype *gpu_results, const int size) {
    char passed = true;
    for (int i = 0; i < size; i++) {
        if (cpu_results[i] != gpu_results[i]) {
            passed = false;
        }
    }
    if (passed) {
        std::cout << "--cambine:passed:-)" << std::endl;
    } else {
        std::cout << "--cambine: failed:-(" << std::endl;
    }
}

void _clCmdParams(int argc, char* argv[]) {
    for (int i = 1; i < argc; ++i) {
        if (argv[i] == NULL || argv[i][0] != '-') continue;
        switch (argv[i][1]) {
            case 'g':
                if (++i < argc) {
                    std::sscanf(argv[i], "%u", &work_group_size);
                } else {
                    throw std::string("Could not read argument after option -g");
                }
                break;
            case 'd':
                if (++i < argc) {
                    std::sscanf(argv[i], "%u", &device_id_inuse);
                } else {
                    throw std::string("Could not read argument after option -d");
                }
                break;
            case 'p':
                if (++i < argc) {
                    std::sscanf(argv[i], "%u", &platform_id_inuse);
                } else {
                    throw std::string("Could not read argument after option -p");
                }
                break;
            default:
                break;
        }
    }
}

void run_bfs_cpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size,
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask,
                 char *h_graph_visited, int *h_cost_ref) {
    (void)edge_list_size;
    char stop;
    int k = 0;
    do {
        stop = false;
        for (int tid = 0; tid < no_of_nodes; tid++) {
            if (h_graph_mask[tid] == true) {
                h_graph_mask[tid] = false;
                for (int i = h_graph_nodes[tid].starting;
                     i < (h_graph_nodes[tid].no_of_edges + h_graph_nodes[tid].starting); i++) {
                    int id = h_graph_edges[i];
                    if (!h_graph_visited[id]) {
                        h_cost_ref[id] = h_cost_ref[tid] + 1;
                        h_updating_graph_mask[id] = true;
                    }
                }
            }
        }

        for (int tid = 0; tid < no_of_nodes; tid++) {
            if (h_updating_graph_mask[tid] == true) {
                h_graph_mask[tid] = true;
                h_graph_visited[tid] = true;
                stop = true;
                h_updating_graph_mask[tid] = false;
            }
        }
        k++;
    } while (stop);
}

void run_bfs_gpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size,
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask,
                 char *h_graph_visited, int *h_cost) {
    (void)edge_list_size;

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
    gettimeofday(&tv_mem_alloc_start, NULL);
    tvsub(&tv_mem_alloc_start, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    std::vector<int> graph_mask(no_of_nodes);
    std::vector<int> updating_graph_mask(no_of_nodes);
    std::vector<int> graph_visited(no_of_nodes);
    std::vector<int> cost(no_of_nodes);

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    gettimeofday(&tv_h2d_start, NULL);
#endif

#pragma omp parallel for
    for (int i = 0; i < no_of_nodes; i++) {
        graph_mask[i] = (int)h_graph_mask[i];
        updating_graph_mask[i] = (int)h_updating_graph_mask[i];
        graph_visited[i] = (int)h_graph_visited[i];
        cost[i] = h_cost[i];
    }

#ifdef TIMING
    gettimeofday(&tv_h2d_end, NULL);
    tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
    h2d_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef PROFILING
    timer kernel_timer;
    double kernel_time_profile = 0.0;
    kernel_timer.reset();
    kernel_timer.start();
#endif

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    char h_over;
    do {
        h_over = false;

#pragma omp parallel for schedule(static)
        for (int tid = 0; tid < no_of_nodes; tid++) {
            if (graph_mask[tid]) {
                graph_mask[tid] = false;
                int new_cost = cost[tid] + 1;
                int start = h_graph_nodes[tid].starting;
                int end = h_graph_nodes[tid].no_of_edges + h_graph_nodes[tid].starting;
                for (int i = start; i < end; i++) {
                    int id = h_graph_edges[i];
                    if (!graph_visited[id]) {
#pragma omp atomic write
                        cost[id] = new_cost;
#pragma omp atomic write
                        updating_graph_mask[id] = 1;
                    }
                }
            }
        }

        int over = 0;
#pragma omp parallel for reduction(|:over) schedule(static)
        for (int tid = 0; tid < no_of_nodes; tid++) {
            if (updating_graph_mask[tid]) {
                graph_mask[tid] = true;
                graph_visited[tid] = true;
                over = 1;
                updating_graph_mask[tid] = false;
            }
        }
        h_over = (char)over;
    } while (h_over);

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    gettimeofday(&tv_d2h_start, NULL);
#endif

#pragma omp parallel for
    for (int i = 0; i < no_of_nodes; i++) {
        h_cost[i] = cost[i];
    }

#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef PROFILING
    kernel_timer.stop();
    kernel_time_profile = kernel_timer.getTimeInSeconds();
    std::cout << "kernel time(s):" << kernel_time_profile << std::endl;
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}

void Usage(int argc, char** argv) {
    (void)argc;
    fprintf(stderr, "Usage: %s <input_file> [-p platform] [-d device] [-t gpu(0)/cpu(1)]\n", argv[0]);
}

int main(int argc, char * argv[]) {
    int no_of_nodes = 0;
    int edge_list_size = 0;
    FILE *fp = NULL;
    Node* h_graph_nodes = NULL;
    char *h_graph_mask = NULL, *h_updating_graph_mask = NULL, *h_graph_visited = NULL;
    int *h_graph_edges = NULL;
    int *h_cost = NULL;
    int *h_cost_ref = NULL;

    try {
        char *input_f;
        if (argc < 2) {
            Usage(argc, argv);
            std::exit(0);
        }

        _clCmdParams(argc, argv);
        input_f = argv[1];
        printf("Reading File\n");

        fp = std::fopen(input_f, "r");
        if (!fp) {
            printf("Error Reading graph file\n");
            return 0;
        }

        int source = 0;

        std::fscanf(fp, "%d", &no_of_nodes);

        int num_of_blocks = 1;
        int num_of_threads_per_block = no_of_nodes;

        if (no_of_nodes > MAX_THREADS_PER_BLOCK) {
            num_of_blocks = (int)std::ceil(no_of_nodes / (double)MAX_THREADS_PER_BLOCK);
            num_of_threads_per_block = MAX_THREADS_PER_BLOCK;
        }
        (void)num_of_blocks;
        work_group_size = num_of_threads_per_block;

        h_graph_nodes = (Node*)std::malloc(sizeof(Node) * no_of_nodes);
        h_graph_mask = (char*)std::malloc(sizeof(char) * no_of_nodes);
        h_updating_graph_mask = (char*)std::malloc(sizeof(char) * no_of_nodes);
        h_graph_visited = (char*)std::malloc(sizeof(char) * no_of_nodes);

        int start, edgeno;

        for (int i = 0; i < no_of_nodes; i++) {
            std::fscanf(fp, "%d %d", &start, &edgeno);
            h_graph_nodes[i].starting = start;
            h_graph_nodes[i].no_of_edges = edgeno;
            h_graph_mask[i] = false;
            h_updating_graph_mask[i] = false;
            h_graph_visited[i] = false;
        }

        std::fscanf(fp, "%d", &source);
        source = 0;

        h_graph_mask[source] = true;
        h_graph_visited[source] = true;
        std::fscanf(fp, "%d", &edge_list_size);
        int id, cost;
        h_graph_edges = (int*)std::malloc(sizeof(int) * edge_list_size);
        for (int i = 0; i < edge_list_size; i++) {
            std::fscanf(fp, "%d", &id);
            std::fscanf(fp, "%d", &cost);
            h_graph_edges[i] = id;
        }

        if (fp)
            std::fclose(fp);
        fp = NULL;

        h_cost = (int*)std::malloc(sizeof(int) * no_of_nodes);
        h_cost_ref = (int*)std::malloc(sizeof(int) * no_of_nodes);
        for (int i = 0; i < no_of_nodes; i++) {
            h_cost[i] = -1;
            h_cost_ref[i] = -1;
        }
        h_cost[source] = 0;
        h_cost_ref[source] = 0;

        run_bfs_gpu(no_of_nodes, h_graph_nodes, edge_list_size, h_graph_edges,
                    h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost);

        for (int i = 0; i < no_of_nodes; i++) {
            h_graph_mask[i] = false;
            h_updating_graph_mask[i] = false;
            h_graph_visited[i] = false;
        }

        source = 0;
        h_graph_mask[source] = true;
        h_graph_visited[source] = true;
        run_bfs_cpu(no_of_nodes, h_graph_nodes, edge_list_size, h_graph_edges,
                    h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost_ref);

        compare_results<int>(h_cost_ref, h_cost, no_of_nodes);

        std::free(h_graph_nodes);
        std::free(h_graph_mask);
        std::free(h_updating_graph_mask);
        std::free(h_graph_visited);
        std::free(h_graph_edges);
        std::free(h_cost);
        std::free(h_cost_ref);
    } catch (std::string msg) {
        std::cout << "--cambine: exception in main ->" << msg << std::endl;
        if (fp) std::fclose(fp);
        std::free(h_graph_nodes);
        std::free(h_graph_mask);
        std::free(h_updating_graph_mask);
        std::free(h_graph_visited);
        std::free(h_graph_edges);
        std::free(h_cost);
        std::free(h_cost_ref);
    }

    return 0;
}
